    /// <summary>
    /// Purchases tickets using optimistic concurrency control with retry logic.
    /// Uses EF Core's RowVersion/Timestamp for conflict detection.
    /// </summary>
    public async Task<PurchaseResult> PurchaseTicketsAsync(
        int eventId,
        string customerEmail,
        int quantity,
        CancellationToken cancellationToken = default)
    {
        if (quantity <= 0)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero."
            };
        }

        if (quantity > MaxTicketsPerPurchase)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = $"Cannot purchase more than {MaxTicketsPerPurchase} tickets at once."
            };
        }

        if (string.IsNullOrWhiteSpace(customerEmail))
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Customer email is required."
            };
        }

        for (int attempt = 0; attempt < MaxRetries; attempt++)
        {
            try
            {
                return await AttemptPurchaseWithOptimisticConcurrency(
                    eventId, customerEmail, quantity, cancellationToken);
            }
            catch (DbUpdateConcurrencyException)
            {
                if (attempt == MaxRetries - 1)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = "Unable to complete purchase due to high demand. Please try again."
                    };
                }

                // Exponential backoff before retry
                await Task.Delay(TimeSpan.FromMilliseconds(50 * Math.Pow(2, attempt)), cancellationToken);
            }
        }

        return new PurchaseResult
        {
            Success = false,
            Message = "Purchase failed after maximum retries."
        };
    }

    private async Task<PurchaseResult> AttemptPurchaseWithOptimisticConcurrency(
        int eventId,
        string customerEmail,
        int quantity,
        CancellationToken cancellationToken)
    {
        await using var context = await _contextFactory.CreateDbContextAsync(cancellationToken);
        await using var transaction = await context.Database.BeginTransactionAsync(
            System.Data.IsolationLevel.RepeatableRead, cancellationToken);

        try
        {
            // Read the event with current row version
            var eventEntity = await context.Events
                .FirstOrDefaultAsync(e => e.EventId == eventId, cancellationToken);

            if (eventEntity == null)
            {
                return new PurchaseResult
                {
                    Success = false,
                    Message = "Event not found."
                };
            }

            // Validate available seats
            if (eventEntity.AvailableSeats < quantity)
            {
                return new PurchaseResult
                {
                    Success = false,
                    Message = $"Not enough seats available. Only {eventEntity.AvailableSeats} seats remaining."
                };
            }

            // Update inventory (optimistic concurrency via RowVersion)
            eventEntity.AvailableSeats -= quantity;

            // Record the purchase
            var purchase = new TicketPurchase
            {
                EventId = eventId,
                CustomerEmail = customerEmail,
                Quantity = quantity,
                PurchasedAt = DateTime.UtcNow
            };

            context.TicketPurchases.Add(purchase);

            // SaveChanges will throw DbUpdateConcurrencyException if RowVersion has changed
            await context.SaveChangesAsync(cancellationToken);
            await transaction.CommitAsync(cancellationToken);

            return new PurchaseResult
            {
                Success = true,
                Message = $"Successfully purchased {quantity} ticket(s).",
                PurchaseId = purchase.PurchaseId
            };
        }
        catch (DbUpdateConcurrencyException)
        {
            await transaction.RollbackAsync(cancellationToken);
            throw; // Let the retry loop handle it
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            return new PurchaseResult
            {
                Success = false,
                Message = $"An error occurred: {ex.Message}"
            };
        }
    }

    /// <summary>
