                // Atomic check-and-update using raw SQL with row-level locking
                int rowsAffected = await context.Database.ExecuteSqlRawAsync(
                    @"UPDATE Events 
                      SET AvailableSeats = AvailableSeats - {0} 
                      WHERE EventId = {1} AND AvailableSeats >= {0}",
                    new object[] { quantity, eventId },
                    cancellationToken);

                if (rowsAffected == 0)
                {
                    await transaction.RollbackAsync(cancellationToken);

                    var eventExists = await context.Events
